DROP TABLE IF EXISTS "BusinessCategories";

DROP TABLE IF EXISTS "EventCategories";

CREATE TABLE "EventCategories" (
    "ID" INTEGER PRIMARY KEY AUTOINCREMENT,
    "IsBusinessCategory" INTEGER NULL
);

CREATE TABLE "BusinessCategories" (
    "ID" INTEGER PRIMARY KEY AUTOINCREMENT,
    "BusinessCategoryID" INTEGER NOT NULL REFERENCES "EventCategories" ("ID")
);

CREATE TRIGGER validate_business_category_insert
BEFORE INSERT ON "BusinessCategories"
FOR EACH ROW
BEGIN
    SELECT RAISE(ABORT, 'Referenced EventCategories entry does not have IsBusinessCategory set to 1')
    WHERE (SELECT "IsBusinessCategory" FROM "EventCategories" WHERE "ID" = NEW."BusinessCategoryID") IS NOT 1;
END;

CREATE TRIGGER validate_business_category_update
BEFORE UPDATE OF "BusinessCategoryID" ON "BusinessCategories"
FOR EACH ROW
BEGIN
    SELECT RAISE(ABORT, 'Referenced EventCategories entry does not have IsBusinessCategory set to 1')
    WHERE (SELECT "IsBusinessCategory" FROM "EventCategories" WHERE "ID" = NEW."BusinessCategoryID") IS NOT 1;
END;

CREATE TRIGGER prevent_unflag_business_category
BEFORE UPDATE OF "IsBusinessCategory" ON "EventCategories"
FOR EACH ROW
WHEN NEW."IsBusinessCategory" IS NOT 1
BEGIN
    SELECT RAISE(ABORT, 'Cannot unset IsBusinessCategory while it is referenced by BusinessCategories')
    WHERE EXISTS (SELECT 1 FROM "BusinessCategories" WHERE "BusinessCategoryID" = OLD."ID");
END
